    private BankRecordsService bankRecordsService;

    @Override
    @Transactional(rollbackFor = Exception.class)
    public void saveMaybeExceData(MarginAgroInsideBankRecords bankRecord) {
        System.err.println("当前保存的数据为:" + JSONObject.toJSONString(bankRecord));
        bankRecordsService.save(bankRecord);
        if (bankRecord.getBankId().equals("462712")) {
            int i = 1 / 0;         // 抛出异常，事务回滚
        }
        System.out.println("当前bankId为:" + bankRecord.getBankId());
